def is_s3_path(path: str) -> bool:
    """Check if the path is an S3 path."""
    return path.startswith('s3://') or path.startswith('s3a://')

def is_dynamodb_table(path: str) -> bool:
    """Check if the path refers to a DynamoDB table."""
    return path.startswith('dynamodb://') or path.startswith('dynamodb:')

def parse_s3_path(s3_path: str) -> tuple:
    """Parse S3 path to bucket and key."""
    parsed = urlparse(s3_path)
    bucket = parsed.netloc
    key = parsed.path.lstrip('/')
    return bucket, key

def parse_dynamodb_path(dynamo_path: str) -> str:
    """Parse DynamoDB path to get table name."""
    path = dynamo_path.replace('dynamodb://', '').replace('dynamodb:', '')
    return path

def read_from_s3(s3_path: str, local_path: str = None) -> str:
    """Download file from S3 to local temp location."""
    s3_client = boto3.client('s3')
    bucket, key = parse_s3_path(s3_path)
    
    if local_path is None:
        _, ext = os.path.splitext(key)
        local_path = f"/tmp/{os.path.basename(key)}"
    
    logger.info(f"Downloading from S3: s3://{bucket}/{key} to {local_path}")
    s3_client.download_file(bucket, key, local_path)
    return local_path

def write_to_s3(local_path: str, s3_path: str) -> None:
    """Upload file from local to S3."""
    s3_client = boto3.client('s3')
    bucket, key = parse_s3_path(s3_path)
    
    logger.info(f"Uploading to S3: {local_path} to s3://{bucket}/{key}")
    s3_client.upload_file(local_path, bucket, key)

def read_from_dynamodb(table_name: str, limit: int = None) -> pd.DataFrame:
    """Read data from DynamoDB table into pandas DataFrame."""
    dynamodb = boto3.resource('dynamodb')
    table = dynamodb.Table(table_name)
    
    logger.info(f"Scanning DynamoDB table: {table_name}")
    
    items = []
    scan_kwargs = {}
    if limit:
        scan_kwargs['Limit'] = limit
    
    try:
        response = table.scan(**scan_kwargs)
        items.extend(response.get('Items', []))
        
        if limit is None:
            while 'LastEvaluatedKey' in response:
                response = table.scan(ExclusiveStartKey=response['LastEvaluatedKey'])
                items.extend(response.get('Items', []))
        
        if not items:
            logger.warning(f"No items found in DynamoDB table: {table_name}")
            return pd.DataFrame()
        
        df = pd.DataFrame(items)
        logger.info(f"Read {len(df)} rows from DynamoDB table: {table_name}")
        return df
        
    except ClientError as e:
        logger.error(f"Error reading from DynamoDB: {e}")
        raise

def write_to_dynamodb(df: pd.DataFrame, table_name: str) -> None:
    """Write pandas DataFrame to DynamoDB table."""
    dynamodb = boto3.resource('dynamodb')
    table = dynamodb.Table(table_name)
    
    logger.info(f"Writing {len(df)} rows to DynamoDB table: {table_name}")
    
    items = df.to_dict('records')
    
    with table.batch_writer() as batch:
        for i, item in enumerate(items):
            cleaned_item = {k: ('' if pd.isna(v) else v) for k, v in item.items()}
            batch.put_item(Item=cleaned_item)
            
            if (i + 1) % 100 == 0:
                logger.info(f"Written {i + 1}/{len(items)} items to DynamoDB")
    
    logger.info(f"Successfully wrote all {len(items)} items to DynamoDB")

def get_dynamodb_schema(table_name: str) -> List[str]:
    """Get column names from DynamoDB table."""
    dynamodb = boto3.resource('dynamodb')
    table = dynamodb.Table(table_name)
    
    try:
        response = table.scan(Limit=1)
        items = response.get('Items', [])
        
        if not items:
            logger.warning(f"No items in DynamoDB table: {table_name}")
            return []
        
        return list(items[0].keys())
        
    except ClientError as e:
        logger.error(f"Error getting DynamoDB schema: {e}")
        raise

def load_config_from_s3(s3_path: str) -> dict:
    """Load JSON config file from S3."""
    local_path = read_from_s3(s3_path, "/tmp/config.json")
    with open(local_path, 'r', encoding='utf-8') as f:
        return json.load(f)

